CREATE TABLE IF NOT EXISTS "recipe_components" ("id" integer PRIMARY KEY AUTOINCREMENT NOT NULL, "amount" decimal, "created_at" datetime(6) NOT NULL, "updated_at" datetime(6) NOT NULL, "meal_id" integer NOT NULL, "ingredient_id" integer NOT NULL, CONSTRAINT "fk_rails_0bbec22857"
FOREIGN KEY ("meal_id")
  REFERENCES "meals" ("id")
, CONSTRAINT "fk_rails_01257932b4"
FOREIGN KEY ("ingredient_id")
  REFERENCES "ingredients" ("id")
);
CREATE TABLE IF NOT EXISTS "ingredients" ("id" integer PRIMARY KEY AUTOINCREMENT NOT NULL, "name" varchar, "unit" varchar, "created_at" datetime(6) NOT NULL, "updated_at" datetime(6) NOT NULL, "price" decimal, "quantity" integer);
DELETE FROM sqlite_sequence;
CREATE INDEX "index_recipe_components_on_meal_id" ON "recipe_components" ("meal_id") /*application='RailsSite'*/;
